/**
 * Estrae dal testo del nodo AI (che può contenere ```json ... ```)
 * le variabili:
 *  - "info utili"
 *  - "mail di contatto"
 *  - "partita iva"
 *  - "best_contact_url"
 *  - "contact_urls" (array)
 *
 * Il codice gestisce automaticamente:
 *  - AI con content.parts[0].text
 *  - blocchi ```json ... ```
 *  - fallback sul primo oggetto {...}
 *  - JSON non formattato correttamente
 */

// 1) Recupera il testo dal nodo AI
function getAIText(input) {
  if (typeof input === 'string') return input;
  if (input?.content?.parts?.[0]?.text) return input.content.parts[0].text;
  if (input?.content?.text) return input.content.text;
  if (input?.text) return input.text;
  return JSON.stringify(input);
}

const rawText = getAIText($json) || '';


// 2) Estrarre il blocco JSON tra ```json ... ```
function extractJsonBlock(txt) {
  if (!txt) return null;

  // Cerca blocchi ```json ... ```
  let match = txt.match(/```json\s*([\s\S]*?)```/i);
  if (match && match[1]) return match[1];

  // Cerca blocchi ``` ... ```
  match = txt.match(/```\s*([\s\S]*?)```/i);
  if (match && match[1]) return match[1];

  // Fallback: primo {...} plausibile
  const start = txt.indexOf('{');
  const end = txt.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    return txt.slice(start, end + 1);
  }

  return null;
}

let jsonStr = extractJsonBlock(rawText);


// 3) Sanitizzazione minima
function sanitizeJson(s) {
  if (!s) return s;
  return s
    .replace(/[“”]/g, '"')
    .replace(/[‘’]/g, "'")
    .replace(/,\s*([}\]])/g, '$1')  // virgole finali
    .trim();
}

jsonStr = sanitizeJson(jsonStr);


// 4) Parse sicuro
let parsed = {};
if (jsonStr) {
  try {
    parsed = JSON.parse(jsonStr);
  } catch (e) {
    parsed = {};
  }
}


// 5) Helpers
function safeString(v) {
  return (typeof v === 'string') ? v.trim() : "";
}

function safeArray(v) {
  if (Array.isArray(v)) {
    return v.map(x => (typeof x === 'string' ? x.trim() : "")).filter(Boolean);
  }
  return [];
}


// 6) Estrazione dei nuovi campi
const infoUtili       = safeString(parsed["info utili"]);
const mailContatto    = safeString(parsed["mail di contatto"]);
const partitaIva      = safeString(parsed["partita iva"]);
const bestContactUrl  = safeString(parsed["best_contact_url"]);
const contactUrls     = safeArray(parsed["contact_urls"]);


// 7) Output finale consolidato
return {
  "info utili": infoUtili,
  "mail di contatto": mailContatto,
  "partita iva": partitaIva,
  "best_contact_url": bestContactUrl,
  "contact_urls": contactUrls
};

// 1. Prendi l'input dal nodo Gemini
// Assicurati che il percorso $input.first().json... sia corretto
// In base al tuo esempio, l'input è un array, quindi usiamo $input.item
const inputData = $input.item.json;

// 2. Estrai la stringa di testo dall'output di Gemini
// Il tuo esempio mostrava un array, quindi prendiamo il primo [0]
const geminiOutputString = inputData.content.parts[0].text;

// 3. Pulisci la stringa dai blocchi Markdown
// Questa riga rimuove "```json" (con o senza a capo) e "```"
const jsonString = geminiOutputString
  .replace(/```json\n?|```/g, '')
  .trim();

// 4. Converti (parsa) la stringa pulita in un vero oggetto JSON
try {
  const jsonObject = JSON.parse(jsonString);

  // 5. Restituisci il JSON pulito come output del nodo "Code"
  return { json: jsonObject };

} catch (error) {
  // Gestisce eventuali errori se il JSON non è valido
  console.error("Impossibile parsare il JSON:", error, "Stringa ricevuta:", jsonString);
  return { json: { error: "Errore nel parsing del JSON", rawData: jsonString } };
}

/**
 * Estrae "subject" e "body" dalla risposta del modello AI.
 * L’AI restituisce qualcosa tipo:
 *
 * Oggetto: <testo oggetto>
 *
 * Corpo: <corpo email in HTML>
 */

function extractText(input) {
  if (!input) return "";
  if (typeof input === "string") return input;
  if (input.content?.parts?.[0]?.text) return input.content.parts[0].text;
  if (input.text) return input.text;
  return JSON.stringify(input);
}

let raw = extractText($json);

// Rimuove blocchi markdown se presenti (per sicurezza)
raw = raw.replace(/```[\s\S]*?```/g, "").trim();

// Trova la riga dell'oggetto (case insensitive)
const subjectRegex = /^oggetto:\s*(.+)$/i;
let subject = "";
let body = "";

const lines = raw.split("\n");

// Cerca la riga che contiene "Oggetto:"
for (let i = 0; i < lines.length; i++) {
  const m = lines[i].match(subjectRegex);
  if (m) {
    subject = m[1].trim();
    body = lines.slice(i + 1).join("\n").trim();
    break;
  }
}

// Se non trova "Oggetto:", tenta fallback
if (!subject) {
  subject = (lines[0] || "").trim();
  body = lines.slice(1).join("\n").trim();
}

// 🔧 Rimuovi l'eventuale prefisso "Corpo:" dal body
body = body.replace(/^corpo:\s*/i, "").trim();

// Output finale
return [{
  json: {
    subject,
    body
  }
}];

let url = ($json.Website || "").trim();

// Rimuovi spazi, tab, newline invisibili
url = url.replace(/[\s\r\n\t]+/g, "");

// Porta tutto in minuscolo
url = url.toLowerCase();

// Se inizia con "http://" o "https://" maiuscolo → dopo toLowerCase è risolto
// Se manca lo schema → aggiungi https:// di default
if (url && !/^https?:\/\//.test(url)) {
  url = "https://" + url;
}

// Rimuovi slash multipli finali
url = url.replace(/\/+$/, "");

// Sovrascrivi Website
return [{
  json: {
    ...$json,
    Website: url
  }
}];

// Questo codice va in un nodo "Function" (non "Function Item")

// Data limite: 01/01/2024
const cutoffDate = new Date(2024, 0, 1); // year, month(0-based), day

// Converte una stringa data in formato "dd/mm/yyyy" in un oggetto Date
function parseItalianDate(dateStr) {
  if (typeof dateStr !== 'string') return null;
  const parts = dateStr.split('/');
  if (parts.length !== 3) return null;

  const day = parseInt(parts[0], 10);
  const month = parseInt(parts[1], 10);
  const year = parseInt(parts[2], 10);

  if (isNaN(day) || isNaN(month) || isNaN(year)) return null;

  return new Date(year, month - 1, day);
}

// Converte una data del tipo "04-AUG-25" (formato XML DATA_CONCESSIONE) in Date
function parseXmlDate(dateStr) {
  if (typeof dateStr !== 'string') return null;

  const parts = dateStr.split('-');
  if (parts.length !== 3) return null;

  const day = parseInt(parts[0], 10);
  const monthAbbr = parts[1].toUpperCase();
  const year2 = parseInt(parts[2], 10);

  if (isNaN(day) || isNaN(year2)) return null;

  const months = {
    JAN: 0, FEB: 1, MAR: 2, APR: 3, MAY: 4, JUN: 5,
    JUL: 6, AUG: 7, SEP: 8, OCT: 9, NOV: 10, DEC: 11,
  };

  const month = months[monthAbbr];
  if (month === undefined) return null;

  // Interpreto "25" come 2025, "21" come 2021, ecc.
  const year = year2 <= 49 ? 2000 + year2 : 1900 + year2;

  return new Date(year, month, day);
}

// Parsing dell'importo: prima provo a usare xml.IMPORTO_AGEVOLAZIONE (che è già "pulito"),
// se non c'è o è invalido, allora faccio il parse della stringa elemento_aiuto.
function getImporto(record) {
  // 1) Tentativo con xml.IMPORTO_AGEVOLAZIONE
  if (record.xml && typeof record.xml.IMPORTO_AGEVOLAZIONE === 'string') {
    const numFromXml = parseFloat(
      record.xml.IMPORTO_AGEVOLAZIONE.replace(',', '.')
    );
    if (!isNaN(numFromXml)) {
      return numFromXml;
    }
  }

  // 2) Fallback: parse di elemento_aiuto, es. "€ 1.807,67"
  if (typeof record.elemento_aiuto === 'string') {
    const cleaned = record.elemento_aiuto
      .replace(/[^\d,.-]/g, '') // rimuove caratteri non numerici, lasciando . , - e cifre
      .replace(/\./g, '')       // rimuove il separatore delle migliaia "."
      .replace(',', '.');       // converte la virgola in punto decimale

    const num = parseFloat(cleaned);
    if (!isNaN(num)) {
      return num;
    }
  }

  // Se non riesco a parsare, considero 0
  return 0;
}

// Raccogli tutti i record "bando" da tutti gli items in input.
// Gestisco:
// - items[i].json = [ { car, data, elemento_aiuto, ... }, ... ]
// - items[i].json = { car, data, elemento_aiuto, ... }
let allRecords = [];

for (const item of items) {
  const json = item.json;

  if (Array.isArray(json)) {
    // Caso: items[0].json è un array come nell'esempio che hai fornito
    for (const rec of json) {
      if (rec && typeof rec === 'object') {
        allRecords.push(rec);
      }
    }
  } else if (json && typeof json === 'object') {
    // Caso: ogni item è direttamente un "record"
    allRecords.push(json);
  }
}

// Ora filtro per data (>= 01/01/2024) e sommo elemento_aiuto
let totale = 0;
let countConsiderati = 0;

for (const record of allRecords) {
  // 1) Provo la data esterna, es. record.data = "04/08/2025"
  let recordDate = parseItalianDate(record.data);

  // 2) Se non è valida, provo con xml.DATA_CONCESSIONE, es. "04-AUG-25"
  if (!recordDate && record.xml && typeof record.xml.DATA_CONCESSIONE === 'string') {
    recordDate = parseXmlDate(record.xml.DATA_CONCESSIONE);
  }

  if (!recordDate) {
    continue; // data non valida, salto
  }

  if (recordDate >= cutoffDate) {
    const importo = getImporto(record);
    totale += importo;
    countConsiderati++;
  }
}

// Formatto il totale in stile italiano, es. "€ 8.181,76"
let totaleFormattato;
try {
  const formatted = totale.toLocaleString('it-IT', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });
  totaleFormattato = `€ ${formatted}`;
} catch (e) {
  // In caso l'ambiente Node non supporti bene toLocaleString,
  // restituisco solo il numero grezzo.
  totaleFormattato = totale;
}

// Restituisco un solo item con il totale (stessi output di prima)
return [
  {
    json: {
      dataInizio: '01/01/2024',
      numeroBandiConsiderati: countConsiderati,
      totaleElementoAiuto: totale,                  // numero
      totaleElementoAiutoFormattato: totaleFormattato, // stringa "bella"
    },
  },
];

/**
 * Estrae "subject" e "body" dalla risposta del modello AI.
 * L’AI restituisce qualcosa tipo:
 *
 * Oggetto: <testo oggetto>
 *
 * Corpo: <corpo email in HTML>
 */

function extractText(input) {
  if (!input) return "";
  if (typeof input === "string") return input;
  if (input.content?.parts?.[0]?.text) return input.content.parts[0].text;
  if (input.text) return input.text;
  return JSON.stringify(input);
}

let raw = extractText($json);

// Rimuove blocchi markdown se presenti (per sicurezza)
raw = raw.replace(/```[\s\S]*?```/g, "").trim();

// Trova la riga dell'oggetto (case insensitive)
const subjectRegex = /^oggetto:\s*(.+)$/i;
let subject = "";
let body = "";

const lines = raw.split("\n");

// Cerca la riga che contiene "Oggetto:"
for (let i = 0; i < lines.length; i++) {
  const m = lines[i].match(subjectRegex);
  if (m) {
    subject = m[1].trim();
    body = lines.slice(i + 1).join("\n").trim();
    break;
  }
}

// Se non trova "Oggetto:", tenta fallback
if (!subject) {
  subject = (lines[0] || "").trim();
  body = lines.slice(1).join("\n").trim();
}

// 🔧 Rimuovi l'eventuale prefisso "Corpo:" dal body
body = body.replace(/^corpo:\s*/i, "").trim();

// Output finale
return [{
  json: {
    subject,
    body
  }
}];

// Function Item (Run Once for Each Item)
const baseMinutes = 15;          // tempo medio
const jitterPercent = 0.2;       // ±20%
const min = baseMinutes * (1 - jitterPercent);
const max = baseMinutes * (1 + jitterPercent);

// numero casuale tra min e max
const randomMinutes = Math.floor(Math.random() * (max - min + 1)) + min;

return {
  waitMinutes: randomMinutes
};

// Function Item (Run Once for Each Item)
const baseMinutes = 15;          // tempo medio
const jitterPercent = 0.2;       // ±20%
const min = baseMinutes * (1 - jitterPercent);
const max = baseMinutes * (1 + jitterPercent);

// numero casuale tra min e max
const randomMinutes = Math.floor(Math.random() * (max - min + 1)) + min;

return {
  waitMinutes: randomMinutes
};

// Crea data in formato ISO per Supabase (YYYY-MM-DD)
const oggi = new Date().toISOString().split('T')[0];

// Aggiungi "data_invio" al JSON mantenendo tutto il resto
return [{
  json: {
    ...$json,
    data_invio: oggi
  }
}];

// Crea data in formato ISO per Supabase (YYYY-MM-DD)
const oggi = new Date().toISOString().split('T')[0];

// Aggiungi "data_invio" al JSON mantenendo tutto il resto
return [{
  json: {
    ...$json,
    data_invio: oggi
  }
}];

// Ora limite (24h format) - es. 18 = 18:00
const oraLimite = 18;

// Ottieni ora corrente in timezone Italia
const now = new Date();
const oraCorrente = now.toLocaleString('it-IT', { 
  timeZone: 'Europe/Rome', 
  hour: 'numeric', 
  hour12: false 
});

const ora = parseInt(oraCorrente, 10);

// Se ha superato l'ora limite, forza lo stop
const shouldStopOriginale = $json.should_stop || false;
const shouldStop = ora >= oraLimite ? true : shouldStopOriginale;

return {
  json: {
    ...$json,
    should_stop: shouldStop,
    stopped_by_time_limit: ora >= oraLimite
  }
};

const items = $input.all();

return items.map(item => {
  const obj = item.json;
  // Ricostruisci la stringa dai singoli caratteri (chiavi 0, 1, 2, ...)
  const chars = Object.keys(obj)
    .filter(k => !isNaN(k))
    .sort((a, b) => Number(a) - Number(b))
    .map(k => obj[k]);

  return {
    json: {
      Partita_IVA: chars.join('')
    }
  };
});

